-- Seed current SumiRate data into Supabase/Postgres.
-- Generated from local CSV files. Review before applying.
begin;

on conflict (evaluation_set_id) do update set
    name = excluded.name,
    description = excluded.description,
    status = excluded.status;

on conflict (model_id) do update set
    model_name = excluded.model_name,
    provider = excluded.provider,
    notes = excluded.notes;

on conflict (evaluation_set_id, model_id) do update set
    blind_model_label = excluded.blind_model_label;

on conflict (prompt_id) do update set
    target_style = excluded.target_style,
    prompt_level = excluded.prompt_level,
    prompt_text = excluded.prompt_text,
    expected_elements = excluded.expected_elements,
    forbidden_elements = excluded.forbidden_elements,
    updated_at = now();

on conflict (job_id) do update set
    status = excluded.status,
    attempts = excluded.attempts,
    raw_image_path = excluded.raw_image_path,
    error_code = excluded.error_code,
    error_message = excluded.error_message,
    safety_blocked = excluded.safety_blocked,
    started_at = excluded.started_at,
    finished_at = excluded.finished_at;

on conflict (image_id) do update set
    blind_filename = excluded.blind_filename,
    blind_image_path = excluded.blind_image_path,
    target_style = excluded.target_style,
    prompt_level = excluded.prompt_level,
    prompt_text = excluded.prompt_text,
    expected_elements = excluded.expected_elements,
    forbidden_elements = excluded.forbidden_elements,
    image_width = excluded.image_width,
    image_height = excluded.image_height,
    generated_at = excluded.generated_at;

on conflict (reviewer_id) do update set
    display_name = excluded.display_name,
    password_hash = excluded.password_hash,
    role = excluded.role;

on conflict (evaluation_set_id, image_id, reviewer_id) do update set
    style_consistency_score = excluded.style_consistency_score,
    element_accuracy_score = excluded.element_accuracy_score,
    error_control_score = excluded.error_control_score,
    overall_score = excluded.overall_score,
    error_tags = excluded.error_tags,
    comment = excluded.comment,
    updated_at = excluded.updated_at;

commit;
